const feeds = $input.first().json.feeds;

return feeds.map(feed => ({
  json: {
    name: feed.name,
    url: feed.url
  }
}));

const response = $input.first().json;
let text = response.content[0].text;

text = text.replace(/^[ \t]*\d+\.[ \t]+(?=\*{0,2}(?:Source|Published|Category|Relevance Score|Summary|Suggested Action|Read More))/gm, '- ');
text = text.replace(/^- (\*\*(?:Source|Published|Category|Relevance Score|Summary|Suggested Action|Read More):)/gm, '• $1');

const now = new Date().toLocaleString('[YOUR_LOCALE]', {
  timeZone: '[YOUR_TIMEZONE]',
  dateStyle: 'full',
  timeStyle: 'short'
});
const header = `🛡️ **Threat Intel Digest — ${now}**\n${'─'.repeat(40)}\n`;
const itemBlocks = text.split(/\n(?=\d+\. \*\*)/).filter(b => b.trim());
const chunks = [];
let current = header;
for (const block of itemBlocks) {
  const trimmed = block.trim();
  if ((current + '\n' + trimmed).length > 1950) {
    chunks.push(current.trim());
    current = trimmed;
  } else {
    current += '\n' + trimmed;
  }
}
if (current.trim()) chunks.push(current.trim());
return chunks.map((chunk, i) => ({
  json: {
    discord_message: chunk,
    chunk_index: i + 1,
    total_chunks: chunks.length
  }
}));

const response = $input.first().json;
const text = response.content[0].text;

const now = new Date().toLocaleString('[YOUR_LOCALE]', {
  timeZone: '[YOUR_TIMEZONE]',
  dateStyle: 'full',
  timeStyle: 'short'
});

const html = `<html><body style="font-family: Arial, sans-serif; max-width: 800px; margin: 0 auto; padding: 20px;">
<h2>🛡️ Threat Intel Digest — ${now}</h2>
<hr>
${text
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
  .replace(/&lt;(https?:\/\/[^&]+)&gt;/g, '<a href="$1">$1</a>')
  .replace(/<(https?:\/\/[^\s>]+)>/g, '<a href="$1">$1</a>')
  .replace(/\n[ \t]*- /g, '<br>&bull; ')
  .replace(/\n\n(\d+\.)/g, '<br><br>$1')
  .replace(/\n/g, '<br>')
}
<br><br>
<hr>
<small>AI-Powered Threat Intel Digest</small>
</body></html>`;

return [{
  json: {
    email_subject: `Threat Intel Digest — ${now}`,
    email_body: html
  }
}];

// n8n's Continue on Error merges error info into the output item.
// Feed name/url may survive on $json, or fall back to the SIB node reference.
const feedName = $json.name
  || $('Loop Feeds (SIB)').item.json.name
  || 'Unknown Feed';

const feedUrl = $json.url
  || $('Loop Feeds (SIB)').item.json.url
  || 'Unknown URL';

const error     = $json.error || {};
const statusCode = error.httpCode || error.statusCode || 'N/A';
const errMsg    = error.message || error.description || 'No error detail available';

const ts = new Date().toLocaleString('[YOUR_LOCALE]', {
  timeZone: '[YOUR_TIMEZONE]',
  dateStyle: 'short',
  timeStyle: 'short'
});

const discordContent =
  `⚠️ **RSS Crawl Failure** — ${ts}\n` +
  `**Feed:** ${feedName}\n` +
  `**URL:** <${feedUrl}>\n` +
  `**Status:** \`${statusCode}\`\n` +
  `**Error:** ${errMsg}`;

const gmailSubject = `[TI Digest] RSS Feed Error: ${feedName} (${ts})`;

const gmailHtml =
  `<h3 style="color:#cc0000;">⚠️ RSS Feed Crawl Failure</h3>` +
  `<table cellpadding="6" style="border-collapse:collapse;font-family:monospace;">` +
  `<tr><td><b>Time</b></td><td>${ts}</td></tr>` +
  `<tr><td><b>Feed</b></td><td>${feedName}</td></tr>` +
  `<tr><td><b>URL</b></td><td><a href="${feedUrl}">${feedUrl}</a></td></tr>` +
  `<tr><td><b>Status Code</b></td><td>${statusCode}</td></tr>` +
  `<tr><td><b>Error</b></td><td>${errMsg}</td></tr>` +
  `</table>` +
  `<p style="color:#888;font-size:0.85em;">TI Digest — n8n error monitor</p>`;

return [{
  json: {
    feedName,
    feedUrl,
    statusCode,
    errMsg,
    ts,
    discordContent,
    gmailSubject,
    gmailHtml
  }
}];

// Unpack Feed Fallback (CJS)
const items = $input.all();
const feedMeta = $('Loop Feeds (SIB)').item.json;

if (items.length > 0 && !items[0].json.error) {
  return items.map(item => ({
    json: {
      title:          item.json.title || '',
      link:           item.json.link || '',
      pubDate:        item.json.pubDate || item.json.isoDate || '',
      isoDate:        item.json.isoDate || '',
      contentSnippet: item.json.contentSnippet || item.json.content || '',
      source:         item.json.source || feedMeta.name || 'Unknown',
      feedTitle:      item.json.feedTitle || feedMeta.name || '',
      feedUrl:        item.json.feedUrl || feedMeta.url || ''
    }
  }));
}

return [{
  json: {
    name:   feedMeta.name || 'Unknown',
    url:    feedMeta.url || '',
    source: feedMeta.name || 'Unknown',
    error: {
      message:  items[0]?.json?.error?.message || 'Feed returned no items or failed to parse',
      httpCode: items[0]?.json?.error?.httpCode || 'N/A'
    }
  }
}];

const items = $input.all();
const results = [];

for (const item of items) {
  if (item.json.error) {
    results.push(item);
    continue;
  }

  const feedMeta = $('Loop Feeds (SIB)').item.json;
  const rawXml = item.json.data || item.json.body || '';

  if (!rawXml || rawXml.trim() === '') {
    results.push({
      json: {
        ...feedMeta,
        source: feedMeta.name || 'Unknown',
        error: { message: 'Feed returned empty body', httpCode: 'N/A' }
      }
    });
    continue;
  }

  try {
    const isAtom = rawXml.includes('<entry');
    const itemTag = isAtom ? 'entry' : 'item';
    const itemRegex = new RegExp(`<${itemTag}[\\s>][\\s\\S]*?<\\/${itemTag}>`, 'gi');
    const rawItems = rawXml.match(itemRegex) || [];

    if (rawItems.length === 0) {
      results.push({
        json: {
          ...feedMeta,
          source: feedMeta.name || 'Unknown',
          error: { message: 'Parsed 0 items from feed XML', httpCode: 'N/A' }
        }
      });
      continue;
    }

    // Extract text content between tags, with CDATA support
    const extract = (xml, tag) => {
      const cdataMatch = xml.match(new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>`, 'i'));
      if (cdataMatch) return cdataMatch[1].trim();
      const plainMatch = xml.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i'));
      return plainMatch ? plainMatch[1].replace(/<[^>]+>/g, '').trim() : '';
    };

    // Separate link extractor — handles both RSS <link>url</link> and Atom <link href="url"/>
    const extractLink = (xml) => {
      // Atom self-closing with href attribute
      const atomHref = xml.match(/<link[^>]+href=["']([^"']+)["'][^>]*\/?>/i);
      if (atomHref) return atomHref[1].trim();
      // RSS plain content
      const rssLink = xml.match(/<link[^>]*>([^<\s][^<]*)<\/link>/i);
      if (rssLink) return rssLink[1].trim();
      // Atom <id> fallback
      const atomId = xml.match(/<id[^>]*>([^<]+)<\/id>/i);
      if (atomId) return atomId[1].trim();
      return '';
    };

    for (const raw of rawItems) {
      const link = extractLink(raw);
      // Try all common date fields across RSS 2.0, Atom, and Dublin Core
      const pubDate =
        extract(raw, 'pubDate') ||
        extract(raw, 'published') ||
        extract(raw, 'updated') ||
        extract(raw, 'dc:date') ||
        extract(raw, 'date') ||
        '';

      results.push({
        json: {
          title:          extract(raw, 'title'),
          link,
          pubDate,
          contentSnippet: extract(raw, 'description') || extract(raw, 'summary') || extract(raw, 'content'),
          source:         feedMeta.name || 'Unknown',
          feedTitle:      feedMeta.name,
          feedUrl:        feedMeta.url
        }
      });
    }
  } catch (e) {
    results.push({
      json: {
        ...feedMeta,
        source: feedMeta.name || 'Unknown',
        error: { message: `XML parse error: ${e.message}`, httpCode: 'N/A' }
      }
    });
  }
}

return results;

// Build Triage Payload (CJS)
const SNIPPET_LENGTH = 1000;
const MAX_ITEMS = 100;

let items = $input.first().json.items || [];

if (items.length > MAX_ITEMS) {
  console.warn(`Item count ${items.length} exceeded cap, truncating to ${MAX_ITEMS}`);
  items = items
    .sort((a, b) => new Date(b.pubDate || 0) - new Date(a.pubDate || 0))
    .slice(0, MAX_ITEMS);
}

const clean = (str) => {
  if (!str) return '';
  return String(str)
    .replace(/<[^>]*>/g, ' ')
    .replace(/&[a-z]+;/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
};

const triageItems = items.map((item, idx) => ({
  id: idx,
  title: clean(item.title).slice(0, 200),
  source: item.source || item.creator || 'Unknown',
  snippet: clean(item.contentSnippet || item.content || item.description || '').slice(0, SNIPPET_LENGTH)
}));

const systemPrompt = `You are triaging threat intelligence for a company operating [INSERT YOUR COMPANY INFO].

Analyst environment: [INSERT YOUR ANALYST ENVIRONMENT — e.g. OS, AD, cloud platform, EDR/XDR, SIEM].

Region focus: [INSERT YOUR MONITORED REGIONS — e.g. Southeast Asia, Europe, North America]. Senior practitioner — assume deep security knowledge.

SCORING SCALE (0-10):

- 10: Direct mention of [INSERT YOUR COMPANY NAME] or [INSERT YOUR PRODUCT/PLATFORM NAME]. Actively exploited zero-day in the exact analyst stack ([INSERT YOUR MONITORED VENDOR STACK — e.g. Fortinet, Ivanti, Palo Alto, VMware, Microsoft Exchange, Entra ID, Azure]).
- 8-9: Nation-state actor campaigns against CNI sectors ([INSERT YOUR RELEVANT SECTORS — e.g. energy, utilities, ports, manufacturing]) in any monitored region. Ransomware groups hitting CNI targets in [INSERT YOUR MONITORED REGIONS]. ICS/SCADA/PLC vulnerabilities or active campaigns. Supply chain compromise affecting common security or IT tooling. PAM/privileged access compromise or bypass techniques.
- 6-7: Windows/AD/[INSERT YOUR CLOUD PLATFORM] tradecraft (Kerberoasting, DCSync, ADCS abuse, OAuth abuse, device code phishing, AiTM, token theft, BYOVD). New ransomware TTPs or affiliate activity. AI/LLM security (prompt injection, MCP exploits, model poisoning). Container/Kubernetes escapes. Infostealer campaigns with active distribution, IOCs, traffic analysis, or malware samples. Phishing kits, PhaaS infrastructure, and phishing campaigns abusing legitimate platform notification systems. SIEM/XDR/SOAR detection bypass or evasion tradecraft.
- 4-5: General DFIR and detection engineering content (Sigma, KQL, YARA, Sysmon, Velociraptor, KAPE, memory forensics). MITRE ATT&CK research. Linux/macOS attacks relevant to enterprise. Hardware and low-level attacks. Insider threat cases. CVEs in widely-deployed enterprise libraries with SSRF, auth bypass, or RCE primitives but no confirmed exploitation.
- 2-3: Generic vulnerability disclosures without active exploitation. Security industry news. Tangential research.
- 0-1: Vendor marketing, conference announcements, opinion pieces, consumer security advice, off-topic content.

AUTO-ELEVATION RULES (apply first — these override base scale scores):
- Any item directly mentioning [INSERT YOUR COMPANY NAME] or [INSERT YOUR PRODUCT/PLATFORM NAME] → score 10
- Any actively exploited zero-day or CISA KEV addition → minimum score 8
- Any ransomware or nation-state incident targeting CNI sectors ([INSERT YOUR RELEVANT SECTORS]) in [INSERT YOUR MONITORED REGIONS] → minimum score 9
- Any nation-state or state-nexus threat actor campaign — including newly tracked clusters without established names — targeting CNI sectors or monitored regions → minimum score 8
  (e.g. Volt Typhoon, Salt Typhoon, APT41, APT40, Mustang Panda, Sandworm, APT28, APT29, Lazarus, Kimsuky — treat named groups as examples, not as the boundary)
- Any prompt injection, MCP exploit, or agentic AI compromise → minimum score 7
- Any BYOVD, AiTM phishing, or supply chain attack on dev or security tooling → minimum score 7
- Any PAM bypass, privileged credential theft, or lateral movement via PAM abuse → minimum score 7
- Any CVE or exploit targeting your SIEM, XDR, or SOAR platforms ([INSERT YOUR SIEM/XDR/SOAR PLATFORMS — e.g. Microsoft Sentinel, Defender XDR, Cortex XDR, Rapid7 InsightIDR]) → minimum score 7
- Any CVE affecting [INSERT YOUR CLOUD/PRODUCTIVITY STACK — e.g. M365, Azure, Entra ID, SharePoint, Teams, Defender, Windows AD] (regardless of exploitation status) → minimum score 5
- Any CVE in HTTP client libraries with SSRF or cloud metadata exfiltration primitive — regardless of library name → minimum score 4; if [INSERT YOUR CLOUD PLATFORM — e.g. Azure] or cloud metadata is explicitly mentioned → minimum score 5
  (e.g. Axios, requests, urllib, fetch, got, node-fetch — treat as examples, not as the boundary)
- Any Log4j CVE regardless of variant or severity → minimum score 4
- Detection evasion or obfuscation techniques with clear applicability to Sigma/KQL/YARA/Sysmon detection → minimum score 4
- Any phishing campaign abusing legitimate platform notification infrastructure (email change alerts, push notifications, OAuth consent flows, Teams or Slack external invites) as a delivery mechanism → minimum score 4
- Any infostealer campaign with accompanying IOCs, PCAP, traffic analysis, or malware samples — regardless of stealer family name → minimum score 5
  (e.g. Lumma, Vidar, Atomic, AMOS, Shub, RedLine, Raccoon — treat as examples, not as the boundary)

AUTO-DOWNGRADE RULES (apply before assigning scores in the 2–5 range):
- Third-party OSS CVEs republished through MSRC with no Microsoft product dependency and no active exploitation (wolfSSL, libpng, OpenSC, AppArmor, Polkit, Handlebars.js, Forge, Picomatch, tar-rs, ONNX, Go stdlib, Ruby gems, Rust crates, Python stdlib) → score 2 unless CVSS ≥ 9.0 with confirmed active exploitation or explicit [INSERT YOUR CLOUD PLATFORM]/Windows runtime dependency
- Geographic scope exclusively outside monitored regions ([INSERT YOUR MONITORED REGIONS]) with no transferable threat actor TTPs or techniques → score 2
- Vendor event promotions, conference announcements, sponsored content, or partner posts → score 1
- Weekly or monthly digest roundups and news aggregations without standalone threat detail → score 2
- Financial crime (crypto theft, payment fraud, banking trojans) without infrastructure compromise or CNI targeting → score 2
- Consumer-targeted phishing (generic credential harvest, fake invoice, standard brand impersonation) with no enterprise tradecraft, novel delivery mechanism, or PhaaS infrastructure → score 2

CATEGORIES (use exactly one per item):
"OT/ICS", "IoT/Edge", "Energy/CNI", "AI/LLM", "Windows/AD", "Cloud/IaaS", "Ransomware", "Regional/Nation-State Actor", "Supply Chain", "Vulnerability", "Credential Theft", "Phishing/SocEng", "DFIR/Detection", "macOS", "Linux", "Container/K8s", "Hardware", "Crypto/Financial", "Insider Threat", "General", "Off-topic"

OUTPUT FORMAT:
Return ONLY a valid JSON array. No prose. No markdown code fences. No explanation.

[{"id": 0, "score": 8, "category": "Regional/Nation-State Actor", "reason": "Volt Typhoon TTPs vs US utilities — direct CNI parallel"}]

You MUST return one entry per input item. Do not skip items. Do not invent items. Keep "reason" to one short sentence.`;

const userPrompt = `Score these ${triageItems.length} threat intelligence items:\n\n${JSON.stringify(triageItems, null, 2)}`;

return [{
  json: {
    payload: JSON.stringify({
      model: "claude-haiku-4-5-20251001",
      max_tokens: 8192,
      system: systemPrompt,
      messages: [{ role: "user", content: userPrompt }]
    }),
    originalItems: items,
    itemCount: triageItems.length
  }
}];

const THRESHOLD = 4; // was 3 beofre
const triageResponse = $input.first().json;
const buildPayloadNode = $('Build Triage Payload (CJS)').first().json;
const originalItems = buildPayloadNode.originalItems || [];

let responseText = '';
try {
  responseText = triageResponse.content[0].text;
} catch (e) {
  throw new Error(`Claude triage response malformed: ${JSON.stringify(triageResponse).slice(0, 500)}`);
}

responseText = responseText
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

let scores = [];
try {
  scores = JSON.parse(responseText);
} catch (e) {
  throw new Error(`Failed to parse triage JSON: ${e.message}\nRaw: ${responseText.slice(0, 1000)}`);
}

if (!Array.isArray(scores)) {
  throw new Error(`Triage response is not an array: ${typeof scores}`);
}

const scoreMap = {};
for (const s of scores) {
  if (typeof s.id === 'number') {
    scoreMap[s.id] = s;
  }
}

const runTimestamp = new Date().toISOString();
const survivors = [];
const rejected = [];
const unscored = [];

for (let i = 0; i < originalItems.length; i++) {
  const score = scoreMap[i];
  const base = {
    runTimestamp,
    feedName:       originalItems[i].source || originalItems[i].feedName || originalItems[i].feedSource || '',
    title:          originalItems[i].title || '',
    link:           originalItems[i].link || '',
    pubDate:        originalItems[i].pubDate || '',
    contentSnippet: (originalItems[i].contentSnippet || '').slice(0, 300),
  };

  if (!score) {
    unscored.push({ ...base, triageScore: null, triageCategory: 'UNSCORED', triageReason: 'No Claude response for this index', verdict: 'UNSCORED' });
    continue;
  }

  if (score.score >= THRESHOLD) {
    survivors.push({
      ...originalItems[i],
      triageScore:    score.score,
      triageCategory: score.category || 'Unknown',
      triageReason:   score.reason || ''
    });
  } else {
    rejected.push({ ...base, triageScore: score.score, triageCategory: score.category || 'Unknown', triageReason: score.reason || '', verdict: 'REJECTED' });
  }
}

survivors.sort((a, b) => b.triageScore - a.triageScore);

const survivorRows = survivors.map(s => ({
  runTimestamp,
  feedName:       s.source || s.feedName || s.feedSource || '',
  title:          s.title || '',
  link:           s.link || '',
  pubDate:        s.pubDate || '',
  contentSnippet: (s.contentSnippet || '').slice(0, 300),
  triageScore:    s.triageScore,
  triageCategory: s.triageCategory,
  triageReason:   s.triageReason,
  verdict:        'PASSED'
}));

const auditRows = [...survivorRows, ...rejected, ...unscored];

console.log(`Triage: ${originalItems.length} in → ${survivors.length} passed, ${rejected.length} rejected, ${unscored.length} unscored`);

if (survivors.length === 0) {
  return [{
    json: {
      items: [{
        title: "No relevant items in this window",
        link: "",
        pubDate: new Date().toISOString(),
        source: "TI Digest System",
        contentSnippet: `Pipeline ran. Triaged ${originalItems.length} items, none at or above threshold ${THRESHOLD}.`,
        triageScore: 0,
        triageCategory: "System",
        triageReason: "Placeholder"
      }],
      isEmpty: true,
      triagedCount: originalItems.length,
      auditRows
    }
  }];
}

return [{
  json: {
    items: survivors,
    isEmpty: false,
    triagedCount: originalItems.length,
    survivorCount: survivors.length,
    auditRows
  }
}];

// Decode Claude Response (CJS)
// Sits between Claude Triage HTTP and Parse Filter
// Normalises stream objects, header-wrapped responses, and plain JSON

const raw = $input.first().json;

// Shape 1: Normal — already parsed JSON with content array
if (raw?.content?.[0]?.text && typeof raw.content[0].text === 'string') {
  return [{ json: raw }];
}

// Shape 2: Include Response Headers was ON — body is nested
if (raw?.body) {
  const body = raw.body;

  // Body is already parsed
  if (body?.content?.[0]?.text) {
    return [{ json: body }];
  }

  // Body is a buffer
  if (body?.type === 'Buffer' && Array.isArray(body.data)) {
    const decoded = JSON.parse(Buffer.from(body.data).toString('utf8'));
    return [{ json: decoded }];
  }

  // Body is a stream object
  if (body?._readableState?.buffer) {
    const chunks = body._readableState.buffer;
    const buffers = [];
    for (const chunk of chunks) {
      if (chunk?.type === 'Buffer' && Array.isArray(chunk.data)) {
        buffers.push(Buffer.from(chunk.data));
      } else if (Buffer.isBuffer(chunk)) {
        buffers.push(chunk);
      }
    }
    const decoded = JSON.parse(Buffer.concat(buffers).toString('utf8'));
    return [{ json: decoded }];
  }
}

// Shape 3: Top-level stream object (no header wrapping)
if (raw?._readableState?.buffer) {
  const chunks = raw._readableState.buffer;
  const buffers = [];
  for (const chunk of chunks) {
    if (chunk?.type === 'Buffer' && Array.isArray(chunk.data)) {
      buffers.push(Buffer.from(chunk.data));
    } else if (Buffer.isBuffer(chunk)) {
      buffers.push(chunk);
    }
  }
  const decoded = JSON.parse(Buffer.concat(buffers).toString('utf8'));
  return [{ json: decoded }];
}

// Shape 4: Top-level buffer
if (raw?.type === 'Buffer' && Array.isArray(raw.data)) {
  const decoded = JSON.parse(Buffer.from(raw.data).toString('utf8'));
  return [{ json: decoded }];
}

// Unrecognised — pass through with diagnostic info
throw new Error(`Decode failed. Keys: ${Object.keys(raw || {}).join(', ')} | Sample: ${JSON.stringify(raw).slice(0, 300)}`);

const input = $input.first().json;
const rows = input.auditRows || [];

if (rows.length === 0) return [];  // empty array = no items, downstream nodes don't fire

return rows.map(r => ({ json: r }));

//Filter pubDate 12h
const resolveSource = (item) => {
  const link = item.link || '';
  if (link.includes('thehackernews.com'))            return 'The Hacker News';
  if (link.includes('talosintelligence.com'))        return 'Cisco Talos';
  if (link.includes('krebsonsecurity.com'))          return 'Krebs on Security';
  if (link.includes('rapid7.com'))                   return 'Rapid7 Blog';
  if (link.includes('darkreading.com'))              return 'Dark Reading';
  if (link.includes('bankinfosecurity.com'))         return 'BankInfoSecurity';
  if (link.includes('unit42.paloaltonetworks.com'))  return 'Palo Alto Unit 42';
  if (link.includes('malwarebytes.com'))             return 'Malwarebytes Blog';
  if (link.includes('microsoft.com/en-us/security')) return 'Microsoft Security Blog';
  if (link.includes('isc.sans.edu'))                 return 'SANS ISC';
  if (link.includes('fortiguard.com'))               return 'Fortiguard IR';
  if (link.includes('recordedfuture.com'))           return 'Recorded Future';
  if (link.includes('malware-traffic-analysis.net')) return 'Malware Traffic Analysis';
if (link.includes('cisa.gov'))                     return 'CISA ICS Advisories';
  if (link.includes('bleepingcomputer.com'))         return 'Bleeping Computer';
  if (link.includes('thedfirreport.com'))            return 'The DFIR Report';
  if (link.includes('blogs.jpcert.or.jp'))           return 'JPCERT/CC';
  if (link.includes('elastic.co'))                   return 'Elastic Security Labs';
  if (link.includes('crowdstrike.com'))              return 'CrowdStrike Blog';
  if (link.includes('sentinelone.com'))              return 'SentinelOne Labs';
  if (link.includes('redcanary.com'))                return 'Red Canary';
  if (link.includes('feedburner.com'))               return 'Cisco Talos';
  return 'Unknown';
};

const now = new Date();
const HOURS = 12; // ← testing: 1h. Production: change to 12
const cutoff = new Date(now.getTime() - HOURS * 60 * 60 * 1000);

return $input.all().filter(item => {
  if (item.json.error) return false;

  const pub = item.json.pubDate || item.json.isoDate || item.json.date;

  // No date field = pass through and let Claude triage decide relevance
  // Dropping dateless items here causes BankInfoSecurity/Fortiguard to vanish silently
  if (!pub || pub.trim() === '') return true;

  const parsed = new Date(pub);
  // Unparseable date string = pass through rather than silently drop
  if (isNaN(parsed.getTime())) return true;

  return parsed >= cutoff;

}).map(item => ({
  json: {
    ...item.json,
    feedName: resolveSource(item.json)
  }
}));

// Build Claude Payload (CJS)
const formatPubDate = (item) => {
  const raw = item.pubDate || item.isoDate || item.date || '';
  if (!raw) return 'Unknown date';
  try {
    return new Date(raw).toLocaleString('[INSERT YOUR LOCALE — e.g. [YOUR_LOCALE]]', {
      timeZone: '[INSERT YOUR TIMEZONE — e.g. [YOUR_TIMEZONE]]',
      day: '2-digit',
      month: 'short',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      hour12: false
    }) + ' [INSERT YOUR TIMEZONE ABBREVIATION — e.g. UTC]';
  } catch {
    return raw;
  }
};

const items = $input.first().json.items;

const prompt = `You are a senior threat intelligence analyst. Analyze the following RSS feed items.
Each item has been pre-scored for relevance to [INSERT YOUR ROLE AND COMPANY INFO — e.g. a security analyst at your organisation]. Use the triageScore as the Relevance Score value exactly. Do not adjust it up or down under any circumstances.
Respond in EXACTLY this format for every item. No introduction, no summary, no recommendations, no section headers. ONLY the numbered list. Every field must use a dash prefix. No mixing of bullet styles.
1. **[Title]**
- **Source:** [source]
- **Published:** [pubDate]
- **Category:** [triageCategory]
- **Relevance Score:** [X/10]
- **Summary:** [Two sentences max]
- **Suggested Action:** [Monitor / Investigate / Patch / No action] — [one sentence]
- **Read More:** <[link]>
Example of correct output for one item:
1. **Critical RCE Vulnerability in FortiGate Actively Exploited**
- **Source:** Bleeping Computer
- **Published:** 13 May 2026, 12:00 [INSERT YOUR TIMEZONE ABBREVIATION]
- **Category:** Vulnerability
- **Relevance Score:** 9/10
- **Summary:** A critical RCE flaw in FortiGate firewalls is being actively exploited in the wild. Threat actors are deploying webshells post-exploitation across enterprise targets.
- **Suggested Action:** Patch — apply Fortinet advisory patches immediately and hunt for webshell indicators on perimeter devices.
- **Read More:** <https://www.bleepingcomputer.com/example>
Rules:
- Sort by relevance score descending
- Output ONLY the numbered list — nothing before it, nothing after it
- Every item MUST include all fields including Read More link
- ONLY the title line carries a number (e.g. 1. **Title**) — ALL other fields use ONLY a dash ( - ) prefix, never a number
- Use ONLY dash ( - ) prefix for ALL fields on ALL items, never bullet points ( • ) or numbers
- Never omit any field
- Do NOT indent field lines — every dash must start at the beginning of the line with no leading spaces
- Format ALL URLs with angle brackets exactly like this: <https://example.com> — never use markdown link format
- If the Items array is empty or contains only items with triageScore 0, output exactly this and nothing else: No relevant items passed the triage threshold in this window.
Items:
${JSON.stringify(items.map(i => ({
  title: i.title,
  link: i.link,
  source: i.feedName || i.source || 'Unknown',
  pubDate: formatPubDate(i),
  snippet: (i.contentSnippet || i.content || '').slice(0, 500),
  triageScore: i.triageScore,
  triageCategory: i.triageCategory,
  triageReason: i.triageReason
})))}`;

return [{
  json: {
    payload: JSON.stringify({
      model: "claude-haiku-4-5-20251001",
      max_tokens: 10000,
      messages: [{ role: "user", content: prompt }]
    })
  }
}];

// Accumulate Items (CJS)
const staticData = $getWorkflowStaticData('global');
if (!staticData.accumulatedItems) staticData.accumulatedItems = [];
if (!staticData.feedsProcessed) staticData.feedsProcessed = 0;

const validItems = $input.all()
  .filter(i => !i.json.error && !i.json.signal && (i.json.title || i.json.link))
  .map(i => i.json);

staticData.accumulatedItems.push(...validItems);
staticData.feedsProcessed++;

const allDone = staticData.feedsProcessed >= (staticData.totalFeeds || 21);

return [{ json: { signal: 'feedComplete', allDone } }];

// Read Accumulated Items (CJS)
const staticData = $getWorkflowStaticData('global');
const items = staticData.accumulatedItems || [];
staticData.accumulatedItems = [];
staticData.feedsProcessed = 0;

if (items.length === 0) {
  return [{ json: { error: 'No items collected from any feed' } }];
}

return items.map(item => ({ json: item }));

// Clear Accumulator (CJS)
const staticData = $getWorkflowStaticData('global');
staticData.accumulatedItems = [];
staticData.feedsProcessed = 0;
staticData.totalFeeds = $input.first().json.feeds.length;
return $input.all();
